import { getDefaultConfig } from '@rainbow-me/rainbowkit';
import { base, baseSepolia, bsc, bscTestnet } from 'wagmi/chains';
import { defineChain } from 'viem';

// X Layer Mainnet — custom chain (not built-in to wagmi/viem)
const xlayer = defineChain({
    id: 196,
    name: 'X Layer',
    nativeCurrency: { name: 'OKB', symbol: 'OKB', decimals: 18 },
    rpcUrls: {
        default: { http: ['https://rpc.xlayer.tech'] },
    },
    blockExplorers: {
        default: { name: 'OKX Explorer', url: 'https://www.okx.com/web3/explorer/xlayer' },
    },
});

// X Layer Testnet — custom chain
const xlayerTestnet = defineChain({
    id: 1952,
    name: 'X Layer Testnet',
    nativeCurrency: { name: 'OKB', symbol: 'OKB', decimals: 18 },
    rpcUrls: {
        default: { http: ['https://testrpc.xlayer.tech'] },
    },
    blockExplorers: {
        default: { name: 'OKX Explorer', url: 'https://www.okx.com/web3/explorer/xlayer-test' },
    },
    testnet: true,
});

const networkMode = import.meta.env.VITE_ESCROW_NETWORK_MODE || 'testnet';

const testnetChains = [baseSepolia, bscTestnet, xlayerTestnet] as const;
const mainnetChains = [base, bsc, xlayer] as const;

const chains = networkMode === 'testnet' ? testnetChains : mainnetChains;

export const wagmiConfig = getDefaultConfig({
    appName: 'ClawQuest',
    projectId: import.meta.env.VITE_WALLETCONNECT_PROJECT_ID || 'demo-project-id',
    chains: chains as any,
});

import { REWARD_TYPE } from "@clawquest/shared"

/**
 * Network configuration type
 */
type NetworkConfig = {
    value: string
    label: string
}

/**
 * Mainnet primary networks (default)
 */
const NETWORKS_PRIMARY_MAINNET: readonly NetworkConfig[] = [
    { value: "Base", label: "🔵 Base (8453)" },
    { value: "BNB Smart Chain", label: "🟡 BNB Smart Chain (56)" },
    { value: "Ethereum", label: "✠ Ethereum (1)" },
] as const

/**
 * Testnet primary networks
 */
const NETWORKS_PRIMARY_TESTNET: readonly NetworkConfig[] = [
    { value: "Base Sepolia", label: "🔵 Base Sepolia (84532)" },
    { value: "BNB Smart Chain Testnet", label: "🟡 BNB Smart Chain Testnet (97)" },
] as const

/**
 * Mainnet other networks (default)
 */
const NETWORKS_OTHER_MAINNET: readonly NetworkConfig[] = [
    { value: "Arbitrum One", label: "🔷 Arbitrum One (42161)" },
    { value: "Optimism", label: "🔴 Optimism (10)" },
