// ─── Supported EVM Chains ────────────────────────────────────────────────────

export interface ChainConfig {
    id: number;
    name: string;
    shortName: string;
    nativeCurrency: { symbol: string; name: string; decimals: number };
    rpcUrl: string;
    explorerUrl: string;
    isTestnet: boolean;
}

export const SUPPORTED_CHAINS: Record<string, ChainConfig> = {
    base: {
        id: 8453,
        name: 'Base',
        shortName: 'base',
        nativeCurrency: { symbol: 'ETH', name: 'Ether', decimals: 18 },
        rpcUrl: 'https://mainnet.base.org',
        explorerUrl: 'https://basescan.org',
        isTestnet: false,
    },
    baseSepolia: {
        id: 84532,
        name: 'Base Sepolia',
        shortName: 'base-sepolia',
        nativeCurrency: { symbol: 'ETH', name: 'Ether', decimals: 18 },
        rpcUrl: 'https://sepolia.base.org',
        explorerUrl: 'https://sepolia.basescan.org',
        isTestnet: true,
    },
    bnb: {
        id: 56,
        name: 'BNB Smart Chain',
        shortName: 'bnb',
        nativeCurrency: { symbol: 'BNB', name: 'BNB', decimals: 18 },
        rpcUrl: 'https://bsc-dataseed.binance.org',
        explorerUrl: 'https://bscscan.com',
        isTestnet: false,
    },
    bscTestnet: {
        id: 97,
        name: 'BSC Testnet',
        shortName: 'bsc-testnet',
        nativeCurrency: { symbol: 'tBNB', name: 'Test BNB', decimals: 18 },
        rpcUrl: 'https://data-seed-prebsc-1-s1.binance.org:8545',
        explorerUrl: 'https://testnet.bscscan.com',
        isTestnet: true,
    },
    xlayer: {
        id: 196,
        name: 'X Layer',
        shortName: 'xlayer',
        nativeCurrency: { symbol: 'OKB', name: 'OKB', decimals: 18 },
        rpcUrl: 'https://rpc.xlayer.tech',
        explorerUrl: 'https://www.okx.com/web3/explorer/xlayer',
        isTestnet: false,
    },
    xlayerTestnet: {
        id: 1952,
        name: 'X Layer Testnet',
        shortName: 'xlayer-testnet',
        nativeCurrency: { symbol: 'OKB', name: 'OKB', decimals: 18 },
        rpcUrl: 'https://testrpc.xlayer.tech',
        explorerUrl: 'https://www.okx.com/web3/explorer/xlayer-test',
        isTestnet: true,
    },
} as const;

// ─── Token Registry (per chain) ─────────────────────────────────────────────

export interface TokenInfo {
    address: string;
    decimals: number;
    symbol: string;
    name: string;
}

/** Token registry keyed by chainId → symbol → TokenInfo */
export const TOKEN_REGISTRY: Record<number, Record<string, TokenInfo>> = {
    // Base
    8453: {
        USDC: { address: '0x833589fCD6eDb6E08f4c7C32D4f71b54bdA02913', decimals: 6, symbol: 'USDC', name: 'USD Coin' },
        USDT: { address: '0xfde4C96c8593536E31F229EA8f37b2ADa2699bb2', decimals: 18, symbol: 'USDT', name: 'Tether USD' },
        NATIVE: { address: '0x0000000000000000000000000000000000000000', decimals: 18, symbol: 'ETH', name: 'Ether' },
    },
    // Base Sepolia (testnet)
    84532: {
        USDC: { address: '0xAA87A3f8E6017F1f02af0f306B765FCfBeCac3E4', decimals: 6, symbol: 'USDC', name: 'USD Coin' },
        NATIVE: { address: '0x0000000000000000000000000000000000000000', decimals: 18, symbol: 'ETH', name: 'Ether' },
    },
    // BNB Smart Chain
    56: {
        USDC: { address: '0x8AC76a51cc950d9822D68b83fE1Ad97B32Cd580d', decimals: 18, symbol: 'USDC', name: 'USD Coin' },
        USDT: { address: '0x55d398326f99059fF775485246999027B3197955', decimals: 18, symbol: 'USDT', name: 'Tether USD' },
        NATIVE: { address: '0x0000000000000000000000000000000000000000', decimals: 18, symbol: 'BNB', name: 'BNB' },
    },
    // BSC Testnet
    97: {
        USDT: { address: '0x337610d27c682E347C9cD60BD4b3b107C9d34dDd', decimals: 18, symbol: 'USDT', name: 'Tether USD' },
        NATIVE: { address: '0x0000000000000000000000000000000000000000', decimals: 18, symbol: 'tBNB', name: 'Test BNB' },
    },
    // X Layer
    196: {
        USDC: { address: '0x74b7F16337b8972027F6196A17a631aC6dE26d22', decimals: 6, symbol: 'USDC', name: 'USD Coin' },
        USDT: { address: '0x1E4a5963aBFD975d8c9021ce480b42188849D41d', decimals: 18, symbol: 'USDT', name: 'Tether USD' },
        NATIVE: { address: '0x0000000000000000000000000000000000000000', decimals: 18, symbol: 'OKB', name: 'OKB' },
    },
    // X Layer Testnet
    1952: {
        NATIVE: { address: '0x0000000000000000000000000000000000000000', decimals: 18, symbol: 'OKB', name: 'OKB' },
    },
};

// ─── Helpers ─────────────────────────────────────────────────────────────────

export const NATIVE_TOKEN_ADDRESS = '0x0000000000000000000000000000000000000000';

export function getChainById(chainId: number): ChainConfig | undefined {
    return Object.values(SUPPORTED_CHAINS).find(c => c.id === chainId);
}

export function getTokenInfo(chainId: number, symbol: string): TokenInfo | undefined {
    return TOKEN_REGISTRY[chainId]?.[symbol];
}

export function getTokenByAddress(chainId: number, address: string): TokenInfo | undefined {
    const tokens = TOKEN_REGISTRY[chainId];
    if (!tokens) return undefined;
    return Object.values(tokens).find(t => t.address.toLowerCase() === address.toLowerCase());
}

export function isNativeToken(address: string): boolean {
    return address === NATIVE_TOKEN_ADDRESS;
}

/** Chain IDs supported for escrow deposits */
export const ESCROW_CHAIN_IDS = [8453, 84532, 56, 97, 196, 1952] as const;
export type EscrowChainId = typeof ESCROW_CHAIN_IDS[number];

export type NetworkMode = 'testnet' | 'mainnet';

/** Get chains filtered by network mode */
export function getActiveChains(mode: NetworkMode): ChainConfig[] {
    return Object.values(SUPPORTED_CHAINS).filter(
        c => mode === 'testnet' ? c.isTestnet : !c.isTestnet
    );
}

/** Get active escrow chain IDs filtered by network mode */
export function getActiveEscrowChainIds(mode: NetworkMode): number[] {
    return ESCROW_CHAIN_IDS.filter(id => {
        const chain = getChainById(id);
        return chain && (mode === 'testnet' ? chain.isTestnet : !chain.isTestnet);
    });
}

